export interface ServiceLocaleContent {
  title: string;
  shortTitle: string;
  accentLabel: string;
  heroHeadline: string;
  heroDescription: string;
  partnershipStatement: string;
  seoTitle: string;
  seoDescription: string;
  ogTitle: string;
  ogDescription: string;
  partnershipPoints: PartnershipPoint[];
  capabilities: ServiceCapability[];
  approachSteps: ServiceApproachStep[];
}

function extractEnContent(s: ServiceDetail): ServiceLocaleContent {
  return {
    title: s.title,
    shortTitle: s.shortTitle,
    accentLabel: s.accentLabel,
    heroHeadline: s.heroHeadline,
    heroDescription: s.heroDescription,
    partnershipStatement: s.partnershipStatement,
    seoTitle: s.seoTitle,
    seoDescription: s.seoDescription,
    ogTitle: s.ogTitle,
    ogDescription: s.ogDescription,
    partnershipPoints: s.partnershipPoints,
    capabilities: s.capabilities,
    approachSteps: s.approachSteps,
  };
}

