export function getServiceContent(service: ServiceDetail, locale: string): ServiceLocaleContent {
  if (locale === "en") return extractEnContent(service);
  const t = translations[service.slug]?.[locale as "es" | "fr"];
  return t || extractEnContent(service);
}
